((SELECT id FROM dawah_categories WHERE slug='freedom-human-rights'), 'islam-and-human-rights',
'هل يحترم الإسلام حقوق الإنسان الأساسية؟',
'نعم، يقرر الإسلام حقوقًا أساسية للإنسان بصفته إنسانًا (حرمة الدم، والعرض، والمال، والكرامة) قبل قرون من صياغة الإعلانات الحقوقية الحديثة، وإن اختلفت الصياغة المؤسساتية المعاصرة عن الصياغة الفقهية التقليدية.',
'يقرر الإسلام مبدأ كرامة الإنسان كإنسان بصرف النظر عن دينه أو عرقه كأصل عام: "ولقد كرّمنا بني آدم" خطاب لكل بني آدم لا للمسلمين فقط. من الحقوق التي يكفلها الإسلام كثوابت: حرمة الدم (تحريم القتل الظالم لأي نفس)، وحرمة العرض والمال، وحرية ممارسة الأقليات الدينية لشعائرها، والعدل في القضاء بصرف النظر عن هوية الخصمين. من المهم الاعتراف بأمانة أن بعض تفاصيل الصياغة الفقهية التقليدية لحقوق معينة (كحقوق المرأة أو غير المسلم في بعض السياقات التاريخية) تختلف عن الصياغة المعاصرة لحقوق الإنسان العالمية في بعض التفاصيل، وهذا موضوع نقاش علمي وفقهي مستمر يستحق تناولًا مستقلًا لكل مسألة بعينها لا تعميمًا مبسّطًا في اتجاه واحد.',
'[{"type":"quran","ref":"الإسراء: ٧٠","text":"وَلَقَدْ كَرَّمْنَا بَنِي آدَمَ"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['حقوق الإنسان','كرامة الإنسان'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='science-religion'), 'islam-and-scientific-method',
'هل يرفض الإسلام المنهج العلمي أو نتائجه إجمالًا؟',
'لا — الإسلام يحض على الملاحظة والتجربة والاستدلال العقلي كطريق لفهم الكون، ولا يوجد فيه رفض مبدئي للمنهج العلمي نفسه؛ الخلاف إن وُجد يكون غالبًا حول تفسير معين لنظرية بعينها لا حول العلم كمنهج.',
'المنهج العلمي التجريبي (الملاحظة، الفرضية، الاختبار) لا يتعارض في أصله مع الدعوة القرآنية المتكررة للنظر والتفكر في خلق الله والتدبر في سنن الكون الثابتة. لم يرفض علماء المسلمين تاريخيًا الاشتغال بالعلوم التجريبية، بل أسهموا فيها إسهامًا واسعًا في الطب والفلك والرياضيات والكيمياء خلال قرون ازدهار الحضارة الإسلامية. حين ينشأ خلاف بين مسلمين ونظرية علمية معينة، غالبًا ما يكون الخلاف حول تفسير فلسفي أو ميتافيزيقي مُلحَق بالنظرية (كنفي وجود خالق كنتيجة فلسفية مُقحَمة على نظرية علمية، لا نتيجة علمية ملزمة بذاتها)، لا حول الأداة التجريبية للنظرية نفسها. هذا التمييز الدقيق بين "النتيجة العلمية التجريبية" و"التفسير الفلسفي المُلحَق بها" مهم جدًا لفهم طبيعة أي خلاف حقيقي إن وُجد.',
'[{"type":"quran","ref":"يونس: ١٠١","text":"قُلِ انظُرُوا مَاذَا فِي السَّمَاوَاتِ وَالْأَرْضِ"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['المنهج العلمي','الإسلام والعلم'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='qadar'), 'dua-and-qadar',
'إذا كان كل شيء مقدَّرًا، فما فائدة الدعاء؟',
'الدعاء نفسه سبب من الأسباب التي قدّرها الله ضمن منظومة القدر الشاملة — الله قدّر النتيجة وقدّر أيضًا أن الدعاء أحد أسبابها، فلا تعارض بين الإيمان بالقدر والأخذ بسبب الدعاء.',
'من الأسئلة المتكررة المرتبطة بمسألة القدر: كيف ندعو الله ونطلب تغيير أمر إن كان كل شيء مكتوبًا مسبقًا؟ الجواب الذي يقرره الإسلام: القدر ليس فقط "تقدير النتيجة النهائية" بمعزل عن الأسباب، بل هو تقدير شامل للنتيجة وأسبابها معًا كمنظومة واحدة مترابطة، والدعاء أحد هذه الأسباب التي قدّرها الله ذاته. فحين تدعو الله وتُستجاب دعوتك، فهذا لم يُغيّر "قدرًا سابقًا" بمعزل عن دعائك، بل كان دعاؤك نفسه جزءًا من القدر المكتوب من الأصل. هذا يشبه تمامًا أي سبب آخر يأخذ به الإنسان (كالسعي في طلب الرزق أو العلاج من المرض) دون تعارض مع الإيمان بالقدر — الأخذ بالأسباب المشروعة (ومنها الدعاء) هو تمامًا ما أمر الله به، لا مناقضة له.',
'[{"type":"quran","ref":"غافر: ٦٠","text":"وَقَالَ رَبُّكُمُ ادْعُونِي أَسْتَجِبْ لَكُمْ"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['الدعاء','القضاء والقدر','الأسباب'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='entering-islam'), 'do-i-need-a-witness',
'هل أحتاج شاهدًا أو إمامًا ليصح إسلامي؟',
'لا يُشترط شرعًا وجود شاهد أو إمام أو أي وسيط لصحة نطق الشهادتين — العلاقة بينك وبين الله مباشرة، ووجود شاهد أو مسؤول في مسجد مسألة تنظيمية وتوثيقية اختيارية مفيدة، لا شرط شرعي لصحة الإسلام نفسه.',
'يخلط كثيرون بين أمرين مختلفين: صحة الإسلام شرعًا، وتوثيقه إداريًا. من الناحية الشرعية البحتة، يكفي أن تنطق الشهادتين بقلب مؤمن بمعناهما، ولو كنت وحدك تمامًا بلا حضور أي شخص آخر، ليصح إسلامك أمام الله فورًا. أما التوثيق (كالحصول على "شهادة إسلام" من مركز إسلامي أو مسجد) فهو أمر تنظيمي اختياري قد يفيدك لاحقًا لأغراض عملية (كبعض الإجراءات القانونية في بعض الدول، أو الشعور بدعم مجتمعي)، لكنه ليس شرطًا لصحة إسلامك نفسه. إن كنت تفضّل الخصوصية التامة أو تخشى على سلامتك من الإفصاح لأي جهة، لك أن تكتفي بإسلام سرّي بينك وبين الله دون أي توثيق خارجي إطلاقًا.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['شروط الإسلام','التوثيق','الإسلام السري'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='new-muslim'), 'what-if-i-make-mistakes',
'ماذا لو أخطأت أو نسيت شيئًا بعد إسلامي؟',
'الخطأ والنسيان أمران طبيعيان متوقَّعان في رحلة التعلم، ولا يُبطلان إسلامك ولا ينقصان من قيمته — الله يقبل التوبة دومًا، والاستمرار رغم الأخطاء أهم بكثير من الكمال الفوري المستحيل أصلًا.',
'يخشى كثير من المسلمين الجدد أن يكون أي خطأ أو نسيان (كنسيان صلاة، أو الوقوع في خطأ أخلاقي، أو نطق شيء بالخطأ في الصلاة) دليلًا على "فشل" في الإسلام أو انتقاصًا من صحته. هذا تصور خاطئ تمامًا: الإسلام يقرر صراحة أن الخطأ والنسيان مرفوعان عن المؤاخذة الكاملة ما لم يكونا متعمَّدين، وأن باب التوبة مفتوح دومًا لكل مخطئ دون استثناء، مهما تكرر الخطأ، ما دام هناك ندم وعزم صادق على التحسن. حتى كبار الصالحين عبر التاريخ الإسلامي أخطأوا وتابوا واستمروا. القاعدة العملية المفيدة لك: لا تدع خطأً واحدًا يدفعك للتوقف عن المحاولة كلها — استمر، وتب، وحاول مجددًا، فهذا هو نمط التديّن الصحي المستدام لا استثناءً مخجلًا.',
'[{"type":"quran","ref":"البقرة: ٢٨٦","text":"رَبَّنَا لَا تُؤَاخِذْنَا إِن نَّسِينَا أَوْ أَخْطَأْنَا"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['الخطأ والنسيان','التوبة','الاستمرار'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='sharia'), 'halal-haram-makruh-mustahab',
'ما الفرق بين الحلال والحرام والمكروه والمستحب؟',
'تصنيف فقهي خماسي لكل الأفعال: الواجب (يُثاب فاعله ويُعاقَب تاركه)، المستحب (يُثاب فاعله ولا يُعاقَب تاركه)، المباح (لا ثواب ولا عقاب)، المكروه (يُستحسَن تركه دون عقاب على فعله)، والمحرَّم (يُعاقَب فاعله ويُثاب تاركه).',
'يصنّف الفقه الإسلامي كل الأفعال البشرية ضمن خمس درجات حكمية أوضح كثيرًا من ثنائية "حلال/حرام" الشائعة في الفهم العام المبسَّط: (١) الواجب: مطلوب فعله إلزامًا كالصلوات الخمس، يُعاقَب تاركه بلا عذر. (٢) المستحب (أو المندوب): مطلوب فعله دون إلزام كصلاة النوافل، يُثاب فاعله ولا إثم على تركه. (٣) المباح: لا طلب فيه بفعل ولا ترك، كتفاصيل كثيرة من حياتك اليومية العادية (اختيار نوع الطعام المباح، أو لون الملابس). (٤) المكروه: يُستحسَن تركه دون عقاب على فعله، كبعض آداب السلوك غير الملزمة. (٥) المحرَّم: ممنوع فعله إلزامًا كالكذب والظلم، يأثم فاعله. الفهم الدقيق لهذا التدرج يزيل كثيرًا من التصور المبسَّط الخاطئ بأن كل شيء في الإسلام إما "حلال بحت" أو "حرام قاطع" بلا درجات متوسطة.',
'[]'::jsonb,
'[{"term":"المباح","definition":"ما لا يُطلَب فعله ولا تركه شرعًا، وهو غالب تفاصيل الحياة اليومية العادية."}]'::jsonb,
'[]'::jsonb,
ARRAY['الأحكام التكليفية','الحلال والحرام','الفقه'], 'draft', false)
